  ('social-worker-moex-02871', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '主張「從改善人們和外在環境的適當調合（person-environment fit）」開始，是下列那一種社會工作模式 的說法？', '["優勢模型", "生活模型", "調和模式", "問題解決模型"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02872', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下有關「後現代主義」社會工作觀點的敘述，那一項是錯誤的？', '["後現代社會工作不認為秩序、確定、安全是可實現的", "後現代社會工作強調論述與語言的重要性", "後現代社會工作強調具體行動，即「推論的實踐」（discursive practice ）", "後現代社會工作認為現實與真實是一致的，不是流動的"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02873', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會暨心理學派的實施原則中，以下何種觀點錯誤？', '["應以個別化為原則", "以直接滿足案主需要來協助案主解決問題", "重視案主參與問題研判和處置計畫的建構過程", "社會暨心理服務過程中的決定是不斷修正的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02874', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '學者Mcleod & Meyer（1967）整理出十項社會工作在實務運作中衝突的價值，其中一項是「針對貧窮的 人，有人認為需靠社會集體的力量加以協助；但也有人認為每個人都應該刻苦奮鬥，不應仰賴社會救濟， 成為社會的負擔」，這是屬於何種衝突的價值？', '["集體責任對個人責任（collective responsibility VS. individual responsibility）", "安全滿足對刻苦奮鬥（security-satisfaction VS. struggle, suffering and denial）", "個人自由對社會控制（personal liberty VS. social control）", "相互依賴對個人自治（interdependence VS. individual autonomy）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02875', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Turner（2000）提出社會工作實務可以配合理論著重的重點不同，選擇適合的相關理論，以下有關各理論 著重重點的描述，何者錯誤？', '["理論著重個人是學習者（person as a learner）：行為理論（behavioral theory）", "理論著重個人是個別化的（person as individual）：案主中心取向（client-centered approach）", "理論著重個人是溝通者（person as communicator）：充權觀點（empowerment）", "理論著重個人與世界的關係（person in relation to the universe）：系統理論（system theory）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02876', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '我國社會救助法第11條規定，生活扶助的協助內容以下列何者為原則？', '["機構照顧", "居家照顧", "現金給付", "實物給付"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02877', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依我國社會工作師法，社會工作師及專科社會工作師執業，應接受繼續教育，並於多久提出完成繼續教 育證明文件，以辦理執業執照更新？', '["每四年", "每五年", "每六年", "每七年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02878', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關老人社會工作中常見理論的描述，何者正確？', '["交換理論（exchange theory），該理論指出因為年齡因素，當個人從職場上離開時，相對的也失去了權 力，這是一種社會退縮（social withdrawal）現象", "活動理論（activity theory），該理論指出工作活動是生活中最重要的一環，因此一旦個人離開工作活 動，就需要尋找其他活動以填補工作活動的空缺", "發展理論（developmental theory），強調生命發展週期的影響，尤其是每個週期中個人要如何去因應該 週期的負面影響（negative affection）", "撤退理論（disengagement theory），認為個人面對老化議題時，從心理層面（psychological level）認為 自己不再適宜參與社會，而導致退縮行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02879', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於社會工作教育訓練的描述，下列那一項是正確的？', '["1898年全美社工員協會（National Association of Social Workers）設立，是美國第一個社工專業組織", "1898年倫敦成立第一個慈善組織會社，開始提供睦鄰服務", "美國第一個社會工作員專業組織是「美國社會工作員協會（American Association of Social Workers）」，於 1898年成立", "1898年紐約慈善組織會社於哥倫比亞大學開設社工員專業教育訓練課程，是為社會工作專業訓練之始"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02880', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列那一項不屬於美國NASW所揭櫫的社會工作四大目標？', '["增強人們解決問題、抗衡與發展的能量", "解決人類衝突、促進社會祥和", "連結人與環境體系，以獲得資源、服務與機會", "發展與促進社會政策"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
